<?php
namespace App\Http\Requests;
use Illuminate\Foundation\Http\FormRequest;
class ServiceEntryRequest extends FormRequest{public function authorize(): bool{return true;} public function rules(): array{return ['project_id'=>'required|exists:projects,id','date'=>'required|date','name'=>'required|string|max:255','contractor_id'=>'nullable|exists:contractors,id','pricing_type'=>'required|in:hourly,fixed,unit','hours'=>'required_if:pricing_type,hourly|nullable|numeric|min:0.01','hourly_rate'=>'required_if:pricing_type,hourly|nullable|numeric|min:0','quantity'=>'required_if:pricing_type,unit|nullable|numeric|min:0.001','unit_price'=>'required_if:pricing_type,unit|nullable|numeric|min:0','unit_name'=>'nullable|string|max:50','total_amount'=>'required_if:pricing_type,fixed|nullable|numeric|min:0','payment_status'=>'required|in:paid,unpaid,partial','paid_amount'=>'nullable|numeric|min:0','tag_ids'=>'nullable|array','tag_ids.*'=>'exists:tags,id','comment'=>'nullable|string'];}}
